  try {
    return JSON.parse(configElement.textContent ?? '{}') as PreviewConfig;
  } catch {
    return {};
  }
}

function logicalURL() {
  if (!config.targetOrigin) {
    return window.location.href;
  }

  try {
    const current = new URL(window.location.href);
    return new URL(
      current.pathname + current.search + current.hash,
      config.targetOrigin
    ).href;
  } catch {
    return window.location.href;
  }
}

