  const frame = tab.playwright.frameLocator('iframe[title="Browser preview"]');
  const root = frame.locator('#__yyork-agentation-root');
  const rootCount = await root.count();
  const dataRoot = frame.locator('[data-yyork-browser-agentation="true"]');
  const dataRootCount = await dataRoot.count();
  const scripts = await frame.locator('script[src="/__yyork_browser/agentation.js"]').count();
  const configScripts = await frame.locator('#__yyork-preview-config').count();
  let rootVisible = false;
  if (rootCount === 1) rootVisible = await root.isVisible();
  return { rootCount, dataRootCount, rootVisible, scripts, configScripts };
