func normalizedRequestHostname(host string) string {
	hostname := strings.TrimSpace(host)
	if parsedHost, _, err := net.SplitHostPort(hostname); err == nil {
		hostname = parsedHost
	}
	return strings.ToLower(strings.TrimSuffix(hostname, "."))
