		if err != nil && ctx.Err() == nil {
			return fmt.Errorf("dev: vite: %w", err)
		}
		return nil
	case <-ctx.Done():
		// SIGINT/SIGTERM: let both processes drain.
		appErr := <-appErrCh
		<-viteErrCh
		if appErr != nil && !errors.Is(appErr, context.Canceled) {
			return fmt.Errorf("dev: backend: %w", appErr)
		}
		return nil
	}
}

